import React from 'react';
import { Menu, Row, Col } from 'antd';
import { Link } from 'react-router-dom'; // If you are using React Router

const MegaMenu = () => {
  return (
    <Menu mode="horizontal">
      <Menu.SubMenu title="Mega Menu">
        <Menu.ItemGroup title="Column 1">
          <Row gutter={16}>
            <Col span={6}>
              <Link to="/">Link 1</Link>
            </Col>
            <Col span={6}>
              <Link to="/">Link 2</Link>
            </Col>
            <Col span={6}>
              <Link to="/">Link 3</Link>
            </Col>
            <Col span={6}>
              <Link to="/">Link 4</Link>
            </Col>
          </Row>
        </Menu.ItemGroup>

        <Menu.ItemGroup title="Column 2">
          {/* Add links for the second column */}
        </Menu.ItemGroup>

        <Menu.ItemGroup title="Column 3">
          {/* Add links for the third column */}
        </Menu.ItemGroup>

        <Menu.ItemGroup title="Column 4">
          {/* Add links for the fourth column */}
        </Menu.ItemGroup>

        <Menu.ItemGroup title="Column 5">
          {/* Add links for the fifth column */}
        </Menu.ItemGroup>
      </Menu.SubMenu>
    </Menu>
  );
};

export default MegaMenu;
